function solve(nums) {
    const n = nums.length;

    // 1. Find all divisors of n
    const divisors = new Set();
    for (let i = 1; i * i <= n; i++) {
        if (n % i === 0) {
            divisors.add(i);
            divisors.add(n / i);
        }
    }
    const sortedDivisors = Array.from(divisors).sort((a, b) => a - b);

    // 2. Sort nums to get the target array S
    const S = [...nums].sort((a, b) => a - b);

    /**
     * Checks if array A is a cyclic shift of array B. Assumes |A| = |B| = k.
     * This check runs in O(k^2) time due to exhaustive rotation checking, 
     * which is necessary without using advanced string algorithms (KMP/Z-algorithm)
     * for arrays in standard JS environment.
     */
    const checkCyclicShift = (A, B) => {
        const k = A.length;
        if (k === 0) return true;
        if (k === 1) return A[0] === B[0];

        // 1. Multiset check (O(k))
        const freqA = new Map();
        const freqB = new Map();
        for (const x of A) {
            freqA.set(x, (freqA.get(x) || 0) + 1);
        }
        for (const x of B) {
            freqB.set(x, (freqB.get(x) || 0) + 1);
        }

        if (freqA.size !== freqB.size) return false;
        for (const [key, count] of freqA) {
            if (freqB.get(key) !== count) {
                return false;
            }
        }

        // 2. Sequence matching (Check all k rotations) (O(k^2))
        for (let j = 0; j < k; j++) { // j is the rotation offset (starting point in B)
            let match = true;
            for (let i = 0; i < k; i++) {
                // A[i] must match the element B[(i + j) % k]
                if (A[i] !== B[(i + j) % k]) {
                    match = false;
                    break;
                }
            }
            if (match) return true;
        }

        return false;
    };

    let totalSum = 0;

    // 3. Loop over divisors k
    for (const k of sortedDivisors) {
        let isSortable = true;

        // 4. Check every block
        for (let i = 0; i * k < n; i++) {
            const startIndex = i * k;

            // Extract actual block Bi from nums
            const Bi = nums.slice(startIndex, startIndex + k);

            // Extract target block Ti from sorted array S
            const Ti = S.slice(startIndex, startIndex + k);

            // Check if Bi can be transformed into Ti via cyclic shifts
            if (!checkCyclicShift(Bi, Ti)) {
                isSortable = false;
                break;
            }
        }

        // 5. Sum k if sortable
        if (isSortable) {
            totalSum += k;
        }
    }

    return totalSum;
}

